<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Sorting Algorithm Visualizer</title>
  <style>
    body {
      background-color: #121212;
      color: #e0e0e0;
      font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      margin: 0;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      min-height: 100vh;
    }

    .container {
      width: 90%;
      max-width: 800px;
      display: flex;
      flex-direction: column;
      gap: 24px;
      align-items: center;
    }

    h1 {
      margin: 0;
      font-weight: 500;
      letter-spacing: 0.5px;
      color: #ffffff;
    }

    .controls {
      display: flex;
      gap: 12px;
    }

    button {
      background-color: #2a2a2a;
      color: #ffffff;
      border: 1px solid #3a3a3a;
      padding: 10px 20px;
      font-size: 0.95rem;
      font-weight: 500;
      cursor: pointer;
      border-radius: 6px;
      transition: background-color 0.2s, border-color 0.2s;
    }

    button:hover {
      background-color: #3a3a3a;
      border-color: #4a4a4a;
    }

    button:active {
      background-color: #202020;
    }

    #sort {
      background-color: #03dac6;
      color: #121212;
      border: none;
      font-weight: 600;
    }

    #sort:hover {
      background-color: #01bfa5;
    }

    #sort:active {
      background-color: #00a38c;
    }

    #bars {
      display: flex;
      align-items: flex-end;
      justify-content: center;
      gap: 4px;
      width: 100%;
      height: 350px;
      background-color: #1e1e1e;
      border: 1px solid #2d2d2d;
      border-radius: 8px;
      padding: 16px;
      box-sizing: border-box;
    }

    .bar {
      flex: 1;
      background-color: #3700b3;
      border-top-left-radius: 3px;
      border-top-right-radius: 3px;
      transition: background-color 0.1s ease;
    }

    .bar.active {
      background-color: #cf6679;
    }

    .bar.sorted {
      background-color: #03dac6;
    }
  </style>
</head>
<body>

  <div class="container">
    <h1>Sorting Visualizer</h1>

    <div class="controls">
      <button id="sort">Sort</button>
      <button id="shuffle">Shuffle</button>
      <button id="reset">Reset</button>
    </div>

    <div id="bars"></div>
  </div>

  <script>
    let array = [];
    let initialArray = [];
    let sortState = { i: 0, limit: 0, swapped: false, active: false };
    let animationFrameId = null;
    let isSortingAnimated = false;

    // Helper to generate a random array
    function generateRandomArray(size = 30) {
      const arr = [];
      for (let i = 0; i < size; i++) {
        arr.push(Math.floor(Math.random() * 90) + 10); // Values between 10 and 100
      }
      return arr;
    }

    // Helper to check if array is sorted ascending
    function isSorted(arr) {
      for (let k = 0; k < arr.length - 1; k++) {
        if (arr[k] > arr[k + 1]) return false;
      }
      return true;
    }

    // Redraw the bars in the DOM
    function redraw(activeIndex = -1) {
      const container = document.getElementById('bars');
      container.innerHTML = '';
      if (array.length === 0) return;

      const maxVal = Math.max(...array);
      const sorted = isSorted(array);

      array.forEach((val, idx) => {
        const bar = document.createElement('div');
        bar.className = 'bar';
        // Height proportional to value
        bar.style.height = `${(val / maxVal) * 100}%`;

        if (sorted) {
          bar.classList.add('sorted');
        } else if (idx === activeIndex || idx === activeIndex + 1) {
          bar.classList.add('active');
        }

        container.appendChild(bar);
      });
    }

    // Initialize state for Bubble Sort
    function initSortState() {
      sortState = {
        i: 0,
        limit: array.length - 1,
        swapped: false,
        active: true
      };
    }

    // Programmatic API
    window.viz = {
      array() {
        return array;
      },
      setArray(a) {
        stopAnimation();
        array = [...a];
        initialArray = [...a];
        sortState.active = false;
        redraw();
      },
      sortStep() {
        if (isSorted(array)) {
          redraw();
          return true;
        }
        if (!sortState.active || sortState.limit === undefined || sortState.limit >= array.length) {
          initSortState();
        }

        let currentActive = -1;
        if (sortState.limit > 0) {
          const idx = sortState.i;
          currentActive = idx;
          if (array[idx] > array[idx + 1]) {
            const temp = array[idx];
            array[idx] = array[idx + 1];
            array[idx + 1] = temp;
            sortState.swapped = true;
          }

          sortState.i++;

          if (sortState.i >= sortState.limit) {
            if (!sortState.swapped) {
              sortState.limit = 0; // Already sorted, stop
            } else {
              sortState.limit--;
              sortState.i = 0;
              sortState.swapped = false;
            }
          }
        }

        redraw(currentActive);
        return isSorted(array);
      },
      sorted() {
        return isSorted(array);
      }
    };

    // Animation Loop Control
    function stopAnimation() {
      isSortingAnimated = false;
      if (animationFrameId) {
        clearTimeout(animationFrameId);
        animationFrameId = null;
      }
      document.getElementById('sort').textContent = 'Sort';
    }

    function animateSort() {
      if (!isSortingAnimated) return;

      const done = window.viz.sortStep();
      if (done) {
        stopAnimation();
        redraw();
      } else {
        // Control animation speed (approx 50ms per step)
        animationFrameId = setTimeout(() => {
          if (isSortingAnimated) {
            animateSort();
          }
        }, 50);
      }
    }

    // UI Event Listeners
    document.getElementById('sort').addEventListener('click', () => {
      if (isSortingAnimated) {
        stopAnimation();
      } else {
        if (window.viz.sorted()) return;
        isSortingAnimated = true;
        document.getElementById('sort').textContent = 'Pause';
        animateSort();
      }
    });

    document.getElementById('shuffle').addEventListener('click', () => {
      stopAnimation();
      const shuffled = generateRandomArray(30);
      window.viz.setArray(shuffled);
    });

    document.getElementById('reset').addEventListener('click', () => {
      stopAnimation();
      window.viz.setArray(initialArray);
    });

    // Initial Setup
    const defaultArray = generateRandomArray(30);
    window.viz.setArray(defaultArray);
  </script>
</body>
</html>
